-- DIBUJO TÉCNICO (15 textos EBAU)
-- =====================================================

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('dibujo-tecnico', 'bachillerato', '{2}', 'Sistema diédrico avanzado: abatimientos',
'En el sistema diédrico, el abatimiento es una operación que permite representar en verdadera magnitud una figura plana inclinada respecto a los planos de proyección. Consiste en girar el plano que contiene la figura alrededor de su traza horizontal (o vertical) hasta hacerlo coincidir con el plano horizontal (o vertical) de proyección, de modo que la figura queda representada en verdadero tamaño y forma sin deformaciones. El eje de giro es la traza del plano y los puntos siguen arcos de circunferencia perpendiculares a dicho eje; cada uno recorre un ángulo igual al que forma el plano con el de proyección.

El procedimiento clásico consiste en determinar, para cada punto de la figura, su distancia real al eje de abatimiento y trazar con ese radio un arco desde su proyección sobre el eje hasta alcanzar la posición abatida. El abatimiento permite resolver problemas que en vista diédrica directa serían muy complicados: determinar ángulos reales entre rectas de un plano oblicuo, dibujar polígonos regulares inscritos en él, hallar intersecciones con exactitud o dimensionar piezas inclinadas. Una vez resuelta la figura en verdadera magnitud, puede realizarse el proceso inverso (desabatimiento) para devolverla a su posición espacial original, manteniendo las relaciones proporcionales. Junto al abatimiento, los cambios de plano y los giros constituyen el trío de transformaciones básicas del sistema diédrico. Un cambio de plano sustituye uno de los planos de proyección por otro paralelo a un elemento de la pieza, colocándolo en posición favorable sin modificar la pieza en sí. Un giro, en cambio, hace girar la pieza alrededor de un eje vertical u horizontal mientras los planos de proyección permanecen fijos. Dominar estas tres técnicas es imprescindible en los ejercicios de EBAU sobre sistema diédrico.',
'[{"pregunta":"El abatimiento permite:","opciones":["Hacer invisible una figura","Representar en verdadera magnitud una figura plana inclinada respecto a los planos","Cambiar las escalas","Calcular volúmenes"],"correcta":1},{"pregunta":"El eje de giro en el abatimiento suele ser:","opciones":["El eje X","La traza horizontal o vertical del plano que contiene la figura","La línea de tierra","El centro del plano"],"correcta":1},{"pregunta":"Un cambio de plano consiste en:","opciones":["Mover la pieza","Sustituir un plano de proyección por otro en posición más favorable, sin mover la pieza","Eliminar la pieza","Abatir los puntos"],"correcta":1},{"pregunta":"¿Por qué son útiles los abatimientos en los problemas de EBAU?","opciones":["Porque son muy estéticos","Porque permiten obtener verdaderas magnitudes y resolver ángulos y polígonos","Porque reducen el tamaño","Porque evitan dibujar"],"correcta":1}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{2}', 'Intersecciones de planos y rectas en diédrico',
'Una de las tareas clásicas del sistema diédrico es determinar la intersección entre figuras geométricas. La intersección de dos planos es siempre una recta, salvo que sean paralelos. El procedimiento estándar consiste en hallar dos puntos comunes a los dos planos; la recta que los une es la intersección buscada. Los puntos más fáciles de obtener son los que pertenecen simultáneamente a las trazas homónimas de ambos planos: si dos planos se cortan, sus trazas horizontales se cruzan en un punto de la línea de tierra (o en un punto del plano horizontal), y lo mismo ocurre con las verticales. Uniendo los dos puntos obtenidos, tenemos la recta de intersección con sus dos trazas.

La intersección de una recta con un plano es, en general, un punto. El método clásico consiste en hacer pasar por la recta un plano auxiliar (habitualmente proyectante vertical u horizontal para simplificar), hallar la intersección de este plano auxiliar con el plano dado (que es una recta) y determinar el punto de corte entre esa recta y la recta original: ese punto es la intersección buscada. Esta técnica, aparentemente indirecta, es sistemática y funciona en todos los casos. Cuando se trata de superficies curvas (cilindros, conos, esferas), la intersección es generalmente una curva; se obtiene cortando con planos auxiliares que generen intersecciones sencillas (circunferencias en cilindros de revolución, cónicas en conos, etc.) y localizando suficientes puntos. Estas técnicas son fundamentales en ingeniería y arquitectura para calcular las líneas de corte entre elementos constructivos (ángulos de una cubierta, intersección de ramales de tubería, desarrollos de chapas). En los exámenes EBAU, los ejercicios de intersecciones son frecuentes y requieren no solo conocer el método, sino organizar ordenadamente el trazado para evitar errores acumulativos.',
'[{"pregunta":"La intersección de dos planos es, en general:","opciones":["Un punto","Una recta","Una superficie","Una curva"],"correcta":1},{"pregunta":"Para hallar la intersección de una recta con un plano se suele:","opciones":["Medirla directamente","Hacer pasar un plano auxiliar (proyectante) por la recta y calcular la intersección entre rectas","Extrapolar","Abatir el plano"],"correcta":1},{"pregunta":"La intersección de una superficie cilíndrica con un plano puede ser:","opciones":["Siempre un punto","Una cónica (circunferencia, elipse...)","Una recta","Un rectángulo"],"correcta":1},{"pregunta":"Las intersecciones son fundamentales en ingeniería para:","opciones":["Rellenar planos","Calcular uniones y cortes entre elementos constructivos reales","Pintar","Medir temperaturas"],"correcta":1}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{2}', 'Perspectiva isométrica',
'La perspectiva isométrica es un sistema axonométrico ortogonal en el que los tres ejes del espacio se proyectan sobre el plano del dibujo formando ángulos iguales de 120° entre sí. El nombre procede del griego ("igual medida") y hace referencia a que las escalas a lo largo de los tres ejes son iguales. Esta característica la hace muy intuitiva y fácil de construir, por lo que es la perspectiva preferida en manuales técnicos, instrucciones de montaje, videojuegos clásicos y representaciones rápidas de piezas mecánicas. Los tres ejes suelen orientarse como sigue: uno vertical y los otros dos inclinados 30° respecto a la horizontal.

Las longitudes reales sobre los tres ejes se reducen en la isométrica por un factor teórico llamado coeficiente de reducción, aproximadamente 0,816 (= √(2/3)). En la práctica, la llamada perspectiva isométrica "industrial" o "simplificada" omite esta reducción y usa las medidas reales, lo que produce dibujos ligeramente mayores que los verdaderamente proyectados pero mucho más cómodos y rápidos de construir. Al proyectar circunferencias situadas en planos paralelos a las caras coordenadas, éstas se transforman en elipses cuyo eje mayor coincide con el mayor diámetro aparente del círculo. Una regla muy útil para dibujar estas elipses a mano alzada o con plantillas es la de los cuatro centros: dos arcos de circunferencia de un radio y otros dos de radio diferente conectan tangencialmente para aproximar la elipse. Las ventajas de la isométrica son su sencillez, su aspecto intuitivo y la posibilidad de medir directamente sobre los ejes; sus inconvenientes son que no representa la profundidad con sensación de distancia (objetos lejanos no se ven más pequeños) y que ciertas formas se vuelven ambiguas, problema conocido como "imposibles isométricos" y explotado en los grabados de M.C. Escher.',
'[{"pregunta":"En perspectiva isométrica, los tres ejes proyectados forman entre sí ángulos de:","opciones":["90°","120°","60°","45°"],"correcta":1},{"pregunta":"El coeficiente de reducción teórico sobre los ejes en isométrica verdadera es aproximadamente:","opciones":["1","0,5","0,816 (=√(2/3))","2"],"correcta":2},{"pregunta":"¿Qué forma adopta una circunferencia al proyectarse en un plano coordenado de una isométrica?","opciones":["Un círculo","Una elipse","Una parábola","Un triángulo"],"correcta":1},{"pregunta":"Una desventaja de la isométrica es:","opciones":["Ser difícil de construir","No representar la profundidad con disminución por distancia","Requerir computadoras","Usar colores"],"correcta":1}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{2}', 'Perspectiva cónica: fundamentos',
'La perspectiva cónica es la representación que más fielmente reproduce la visión humana del espacio: los objetos lejanos se ven más pequeños que los cercanos y las líneas paralelas que se alejan convergen hacia puntos de fuga situados en el horizonte. Fue sistematizada en el Renacimiento por artistas y arquitectos italianos como Filippo Brunelleschi y Leon Battista Alberti, que la describió en su tratado De Pictura (1435). Sus elementos son el punto de vista (V, que representa el ojo del observador), el plano del cuadro (plano donde se proyecta el dibujo, perpendicular a la línea de visión), la línea del horizonte (horizontal que pasa por V a la altura del plano del cuadro) y los puntos de fuga (los puntos del horizonte hacia donde convergen las líneas paralelas al suelo).

La perspectiva cónica se clasifica según el número de puntos de fuga. En la de un punto de fuga (frontal), uno de los ejes del objeto es perpendicular al cuadro, y las líneas paralelas a él convergen en un único punto llamado "punto central", situado justo enfrente del observador. Se usa típicamente para representar interiores o pasillos. En la de dos puntos de fuga (oblicua o angular), dos conjuntos de líneas convergen en dos puntos de fuga sobre la línea de horizonte, mientras las líneas verticales permanecen verticales; es el sistema preferido para exteriores de edificios. En la de tres puntos de fuga, también las verticales convergen, hacia un tercer punto por arriba o por abajo, produciendo efectos dramáticos de escorzo usados en vistas aéreas de rascacielos. El método clásico de trazado combina la planta y el alzado con el punto de vista para obtener las proyecciones. En los exámenes EBAU, las preguntas de perspectiva cónica suelen centrarse en el trazado correcto de puntos de fuga, la división proporcional del espacio con segmentos auxiliares y la representación de piezas volumétricas.',
'[{"pregunta":"¿Qué artista renacentista sistematizó la perspectiva cónica?","opciones":["Leonardo da Vinci","Brunelleschi y Alberti","Miguel Ángel","Rafael"],"correcta":1},{"pregunta":"En una perspectiva cónica de dos puntos de fuga:","opciones":["Las verticales también convergen","Las verticales se mantienen verticales y dos conjuntos de líneas convergen en dos puntos del horizonte","Sólo hay un punto de fuga","No hay horizonte"],"correcta":1},{"pregunta":"La línea del horizonte en una perspectiva cónica representa:","opciones":["La base del edificio","La horizontal situada a la altura del ojo del observador","El techo","El suelo"],"correcta":1},{"pregunta":"La perspectiva de tres puntos de fuga se usa especialmente para:","opciones":["Objetos pequeños","Representar rascacielos en vistas muy picadas o contrapicadas","Interiores","Planos topográficos"],"correcta":1}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{2}', 'Normalización: formatos, escalas y líneas',
'La normalización en dibujo técnico es el conjunto de reglas que definen cómo representar e interpretar de forma unívoca los elementos gráficos, garantizando que cualquier técnico del mundo pueda entender y reproducir un mismo plano sin ambigüedad. En España, las normas aplicables son las UNE, alineadas con las internacionales ISO. Los formatos de papel están normalizados por la serie A (ISO 216): el A0 tiene 1 m² de superficie con dimensiones 841×1189 mm, y cada formato sucesivo se obtiene dividiendo por la mitad el lado mayor del anterior, manteniendo la proporción √2. Así, A1 = 594×841, A2 = 420×594, A3 = 297×420, A4 = 210×297. Esta propiedad geométrica hace muy sencillo copiar, reducir y ampliar entre formatos.

Las escalas de representación se expresan como proporciones: 1:1 (escala natural o real), 1:2 (reducción, el dibujo es la mitad que el objeto), 2:1 (ampliación), y similares. Las escalas normalizadas recomendadas son potencias de 1:2, 1:5, 1:10 y sus múltiplos, de modo que sean fáciles de medir con escalímetros. Las líneas empleadas en un plano tienen distintos tipos y grosores según su función: continuas gruesas para aristas visibles y contornos, continuas finas para líneas auxiliares y rayados, discontinuas finas para aristas ocultas, trazo-punto fina para ejes de simetría y trayectorias de elementos móviles, trazo y dos puntos para contornos adyacentes o posiciones extremas. La rotulación también está normalizada en forma, tamaño y proporción (UNE 1-034). El cuadro de rotulación, situado en una esquina del plano, recoge datos imprescindibles: título, escala, fecha, autor, número de plano, tolerancias generales, material. La normalización es la base de la comunicación técnica profesional en ingeniería, arquitectura, fabricación y construcción, y su conocimiento es imprescindible para cualquier titulación técnica.',
'[{"pregunta":"Un formato A3 tiene dimensiones:","opciones":["210×297 mm","297×420 mm","420×594 mm","841×1189 mm"],"correcta":1},{"pregunta":"Si una pieza se dibuja a escala 1:5:","opciones":["El dibujo es 5 veces mayor que la pieza real","El dibujo es 5 veces menor que la pieza real","Son del mismo tamaño","La pieza no tiene dimensiones"],"correcta":1},{"pregunta":"La línea discontinua fina en un plano representa:","opciones":["Aristas visibles","Aristas ocultas","Ejes de simetría","Línea auxiliar"],"correcta":1},{"pregunta":"El formato A0 tiene una superficie de:","opciones":["0,5 m²","1 m²","2 m²","100 cm²"],"correcta":1}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{2}', 'Acotación: reglas y criterios',
'La acotación es la parte del dibujo técnico que indica las dimensiones reales de un objeto, sus tolerancias y sus formas detalladas, de manera que el plano contenga toda la información necesaria para fabricarlo. Una buena acotación debe ser completa (debe incluir todas las medidas necesarias, ni más ni menos), clara (sin ambigüedades), no redundante (cada medida figura una sola vez) y funcional (reflejando la intención del diseñador y la forma de trabajar del fabricante). Los elementos de una cota son la línea de cota (paralela al segmento que acota), las líneas auxiliares (perpendiculares a la de cota y que delimitan el tramo), las flechas o trazos en los extremos, y la cifra numérica que expresa la medida en milímetros (unidad por defecto).

Existen criterios sistemáticos para decidir qué medidas acotar. Se distinguen cotas funcionales (imprescindibles para el uso del elemento, como diámetros de ejes que encajan), cotas no funcionales (medidas auxiliares que ayudan a fabricar) y cotas auxiliares (indicadas entre paréntesis, solo informativas). Hay tres sistemas principales de disposición. En el de cotas en serie, las medidas van una a continuación de otra sumando tolerancias; es sencillo pero acumula errores. En el de cotas en paralelo, todas las medidas parten de una misma referencia; evita la acumulación de errores pero es menos compacto. En el de cotas combinadas, se aprovechan las ventajas de ambos combinándolos con criterio. La acotación también debe indicar tolerancias dimensionales (máxima y mínima variación permitida), tolerancias geométricas (de forma, posición, orientación), rugosidad superficial e indicaciones especiales como roscas, chaflanes o ajustes. La norma UNE-EN ISO 129 regula la acotación. Un plano bien acotado es condición indispensable para la fabricación correcta y cualquier examen EBAU de dibujo técnico incluye ejercicios de acotación.',
'[{"pregunta":"Una cota se compone principalmente de:","opciones":["Línea auxiliar, línea de cota, flechas y cifra","Solo una cifra","Círculo y número","Línea gruesa y color"],"correcta":0},{"pregunta":"¿Qué desventaja tiene la acotación en serie?","opciones":["Es imprecisa","Acumula errores de tolerancias","Ocupa más espacio","Es ilegible"],"correcta":1},{"pregunta":"Las medidas acotadas en un plano se expresan por defecto en:","opciones":["Centímetros","Milímetros","Pulgadas","Metros"],"correcta":1},{"pregunta":"Una buena acotación debe ser:","opciones":["Redundante","Completa, clara, no redundante y funcional","Artística","Mínima"],"correcta":1}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{2}', 'Cortes, secciones y roturas',
'Cuando una pieza tiene partes interiores ocultas (agujeros, cavidades, nervios), su representación mediante líneas discontinuas puede volverse confusa. Para clarificar estas situaciones se emplean cortes y secciones, que "retiran" simbólicamente la parte de la pieza situada entre el observador y un plano imaginario, mostrando lo que hay más allá. Un corte muestra la parte detrás del plano de corte con todas sus aristas visibles; una sección muestra únicamente la superficie cortada, sin representar lo que queda detrás. Las superficies cortadas se rayan con trazos finos paralelos inclinados (45° por defecto), con rayados diferentes para distinguir distintas piezas en un ensamblaje.

Existen varios tipos de corte según sus necesidades. El corte total corta completamente la pieza por un plano, dejándola seccionada en dos mitades. El semicorte (o corte al cuarto), aplicable a piezas simétricas, combina en la misma vista media pieza cortada y media sin cortar, ahorrando una vista. El corte parcial o arrancamiento corta solo una zona limitada de interés, separada del resto por una línea continua fina a mano alzada. El corte por planos paralelos o quebrados permite un plano escalonado para mostrar varios detalles a la vez. Hay reglas importantes: elementos macizos como nervios, tornillos, ejes, radios, dientes de engranaje, remaches, llaves o chavetas no se seccionan longitudinalmente, aunque queden atravesados por el plano de corte, porque representarlos rayados sería confuso. Las roturas, por su parte, se usan en piezas muy largas (ejes, barras, perfiles) para no dibujarlas enteras: se representa solo los extremos y el centro, unidos por una línea quebrada o sinuosa. La acotación incluye la longitud real aunque el dibujo sea recortado. El dominio de estas técnicas es imprescindible para interpretar correctamente planos industriales.',
'[{"pregunta":"La diferencia entre corte y sección es que:","opciones":["No hay diferencia","El corte muestra también lo que queda detrás del plano, la sección solo la superficie cortada","El corte no tiene rayado","La sección no se usa"],"correcta":1},{"pregunta":"Los nervios atravesados longitudinalmente por un plano de corte:","opciones":["Se rayan como el resto","No se seccionan para evitar confusiones","Se eliminan","Se dibujan con color"],"correcta":1},{"pregunta":"Un semicorte se emplea en:","opciones":["Cualquier pieza","Piezas simétricas, combinando media vista exterior y media en corte","Piezas asimétricas","Piezas de madera"],"correcta":1},{"pregunta":"Las roturas sirven para:","opciones":["Mostrar material defectuoso","Representar piezas largas omitiendo una parte central, con la cota real","Indicar peligros","Hacer los dibujos más bonitos"],"correcta":1}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{2}', 'Curvas cónicas: elipse, parábola e hipérbola',
'Las curvas cónicas son las curvas que se obtienen al cortar un cono de revolución con un plano. Fueron estudiadas en profundidad por el matemático griego Apolonio de Pérgamo en el siglo III a.C. en su tratado Las Cónicas, que estableció la mayoría de sus propiedades. Según la inclinación del plano respecto al eje del cono se obtienen distintas curvas: si el plano es perpendicular al eje, una circunferencia (caso particular); si es oblicuo cortando todas las generatrices, una elipse; si es paralelo a una generatriz, una parábola; y si corta ambos mantos del cono (paralelo al eje o más inclinado), una hipérbola. Estas cuatro curvas tienen además una caracterización métrica común: todas son lugares geométricos de puntos que cumplen una relación fija entre sus distancias a un punto fijo (foco) y a una recta fija (directriz), llamada excentricidad: e = 0 (circunferencia), 0 < e < 1 (elipse), e = 1 (parábola), e > 1 (hipérbola).

Las cónicas aparecen por doquier en la ciencia y la tecnología. Las órbitas de los planetas son elipses con el Sol en un foco (primera ley de Kepler). La trayectoria de un proyectil en un campo gravitatorio uniforme (sin resistencia del aire) es una parábola. Las antenas parabólicas, los faros de los coches y los concentradores solares aprovechan la propiedad de la parábola de reflejar hacia un foco los rayos paralelos a su eje. Las elipses tienen la propiedad de reflejar desde un foco al otro, principio aplicado en cámaras anecoicas, bóvedas "susurrantes" y litotricia médica (fragmentar cálculos renales concentrando ondas). Las hipérbolas se encuentran en las trayectorias de partículas que escapan de un campo gravitatorio, en los sistemas de navegación hiperbólica LORAN y en la sombra del Sol en un reloj de sol durante el día. En dibujo técnico, las cónicas se trazan por métodos específicos: por puntos usando la definición bifocal (suma o diferencia de distancias a los focos), por envolventes de tangentes o mediante construcciones que aprovechan propiedades proyectivas.',
'[{"pregunta":"Las cónicas fueron estudiadas en profundidad por:","opciones":["Euclides","Apolonio de Pérgamo en el siglo III a.C.","Pitágoras","Descartes"],"correcta":1},{"pregunta":"La excentricidad de una elipse:","opciones":["Es siempre 1","Está entre 0 y 1","Es mayor que 1","Es negativa"],"correcta":1},{"pregunta":"Una antena parabólica funciona porque:","opciones":["Es plana","Concentra los rayos paralelos al eje en el foco","Refleja por igual en toda la dirección","Usa un espejo plano"],"correcta":1},{"pregunta":"Las órbitas planetarias son:","opciones":["Círculos perfectos","Elipses con el Sol en un foco","Parábolas","Hipérbolas"],"correcta":1}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{2}', 'Tangencias entre circunferencias y rectas',
'Los problemas de tangencias tratan de construir curvas que toquen a otras en puntos comunes (tangentes) sin cortarlas. Son fundamentales en el diseño de piezas mecánicas, trazado de carreteras, vías férreas, engranajes y cualquier situación donde haya que pasar suavemente de una curva a otra evitando cambios bruscos de dirección. El principio que gobierna todas las tangencias entre rectas y circunferencias es sencillo: en el punto de tangencia, el radio de la circunferencia es perpendicular a la recta tangente. Esta propiedad permite abordar sistemáticamente cualquier caso añadiendo puntos auxiliares o circunferencias auxiliares hasta reducirlo a uno conocido.

Los casos fundamentales son tangentes a una circunferencia por un punto exterior (dos soluciones), tangentes comunes a dos circunferencias (hasta cuatro soluciones: dos exteriores y dos interiores), circunferencia tangente a una recta que pase por un punto dado, circunferencia tangente a dos rectas que pase por un punto, y circunferencia tangente a tres rectas (que da lugar a las circunferencias inscrita y exinscritas a un triángulo). Otros casos más complejos son los problemas de Apolonio: trazar una circunferencia tangente a tres elementos dados (puntos, rectas y/o circunferencias), para los que hay hasta 8 combinaciones distintas. La inversión es una transformación geométrica muy poderosa para resolver problemas de tangencias complejos: convierte rectas en circunferencias y viceversa, conservando las tangencias, lo que permite transformar un problema difícil en uno más sencillo. Una aplicación práctica habitual es el trazado de enlaces, curvas que unen dos rectas con un arco de circunferencia tangente a ambas, muy comunes en la geometría de piezas de carpintería metálica, diseños industriales, curvas de autopistas y animaciones. La comprensión profunda de las tangencias es uno de los contenidos más exigentes y recurrentes en EBAU de dibujo técnico.',
'[{"pregunta":"¿Cuál es la propiedad clave de las tangencias entre circunferencias y rectas?","opciones":["Siempre se cortan en dos puntos","En el punto de tangencia, el radio es perpendicular a la recta tangente","Las rectas son paralelas","No pueden existir"],"correcta":1},{"pregunta":"Entre dos circunferencias pueden trazarse como máximo:","opciones":["1 tangente común","2 tangentes","4 tangentes comunes (2 exteriores y 2 interiores)","Ninguna"],"correcta":2},{"pregunta":"Un problema de Apolonio consiste en:","opciones":["Calcular el área","Trazar una circunferencia tangente a tres elementos dados","Dibujar cónicas","Medir ángulos"],"correcta":1},{"pregunta":"Los enlaces entre rectas mediante arcos se aplican en:","opciones":["Carreteras, piezas mecánicas, diseños industriales","Nada práctico","Exclusivamente en arte","Solo en matemáticas puras"],"correcta":0}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{2}', 'Polígonos regulares: construcción',
'Un polígono regular es una figura plana cerrada con todos sus lados iguales y todos sus ángulos interiores iguales. Puede inscribirse siempre en una circunferencia, lo que proporciona el método constructivo más sistemático: dividir la circunferencia en n arcos iguales y unir los puntos de división. La división de la circunferencia en partes iguales es un problema clásico de la geometría griega que fascinó a los matemáticos durante siglos. Gauss demostró en 1796 que un polígono regular de n lados puede construirse con regla y compás si y solo si n es potencia de 2 o producto de potencias de 2 por primos de Fermat distintos (3, 5, 17, 257, 65537). Así, el triángulo equilátero, el cuadrado, el pentágono, el hexágono, el octógono, el decágono o el polígono de 15 lados se construyen exactamente; el heptágono, el eneágono o el endecágono no (se construyen aproximadamente).

Las construcciones clásicas aprovechan propiedades geométricas específicas. El triángulo equilátero se traza inscribiendo en una circunferencia de centro O y radio r arcos de igual radio desde un punto inicial. El cuadrado se obtiene trazando los dos diámetros perpendiculares. El hexágono regular se construye con el radio llevado seis veces sobre la circunferencia, ya que el lado coincide con el radio. El pentágono regular requiere el uso de la proporción áurea, y existe una construcción elegante mediante bisectrices y arcos secundarios. Para polígonos no constructibles con regla y compás se emplean métodos aproximados basados en la división de un diámetro en n partes iguales mediante el teorema de Tales, o la construcción de un heptágono inscrito mediante el lado igual a la mitad del apotema de un triángulo equilátero inscrito (buena aproximación). Los polígonos regulares son estéticamente relevantes, aparecen en muchas estructuras naturales (panales hexagonales, estrellas de mar pentagonales) y son la base para mosaicos y teselaciones arquitectónicas.',
'[{"pregunta":"¿Qué matemático demostró los polígonos constructibles con regla y compás?","opciones":["Euclides","Gauss, en 1796","Newton","Arquímedes"],"correcta":1},{"pregunta":"El lado del hexágono regular inscrito en una circunferencia es igual:","opciones":["Al diámetro","Al radio de la circunferencia","A la mitad del radio","Al doble del radio"],"correcta":1},{"pregunta":"El pentágono regular requiere:","opciones":["Solo una regla","La proporción áurea en su construcción","Tres compases","Coordenadas polares"],"correcta":1},{"pregunta":"Un polígono regular siempre:","opciones":["Tiene más de 10 lados","Puede inscribirse en una circunferencia","Se construye con triángulos","Tiene ángulos rectos"],"correcta":1}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{2}', 'Homología y afinidad',
'La homología es una transformación proyectiva que relaciona dos figuras de modo que rectas correspondientes se cortan en una recta fija llamada eje de homología y puntos correspondientes están alineados con un punto fijo llamado centro de homología. Es decir, dada una figura original, su homóloga se obtiene uniendo cada punto con el centro y localizando su correspondiente sobre la nueva posición, pero con la restricción de que los puntos de la figura que yacen sobre el eje permanecen fijos. Esta transformación es el modelo abstracto que subyace a la perspectiva cónica: la proyección cónica desde el ojo (centro) sobre un cuadro que corta al plano original a lo largo del eje es precisamente una homología.

La afinidad es un caso particular de homología en la que el centro está en el infinito, de modo que las rectas que unen puntos homólogos son paralelas en lugar de concurrentes. La afinidad conserva el paralelismo y la razón simple (cociente de segmentos sobre una misma recta), pero no las longitudes ni los ángulos en general. Un caso aún más particular es la afinidad ortogonal, muy útil en dibujo técnico, que se obtiene proyectando ortogonalmente una figura sobre un plano oblicuo. La aplicación práctica más importante de la afinidad es la construcción de la proyección de una figura plana (círculo, polígono regular) sobre un plano inclinado: la imagen de un círculo por una afinidad es una elipse, cuyo eje mayor coincide con la dirección no deformada y cuyo eje menor está reducido por el coseno del ángulo entre los planos. Esto permite construir elipses como proyección de círculos, lo que simplifica enormemente el trazado en sistema diédrico, en perspectivas axonométricas y en perspectiva caballera. Estas transformaciones geométricas no se limitan a un ejercicio académico, sino que son la base teórica de toda la geometría proyectiva y el antecedente de las transformaciones lineales usadas en gráficos por computador.',
'[{"pregunta":"En una homología, puntos correspondientes están alineados con:","opciones":["El eje","El centro de homología","Un tercer punto","Ninguno"],"correcta":1},{"pregunta":"Una afinidad es una homología en la que:","opciones":["El eje es infinito","El centro está en el infinito, por lo que las rectas de puntos homólogos son paralelas","No hay eje","No se usa"],"correcta":1},{"pregunta":"La imagen de una circunferencia por una afinidad es generalmente:","opciones":["Una circunferencia","Una elipse","Una recta","Un triángulo"],"correcta":1},{"pregunta":"La homología es el modelo abstracto que subyace a:","opciones":["La isometría","La perspectiva cónica","El dibujo cotado","La acotación"],"correcta":1}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{2}', 'Perspectiva caballera',
'La perspectiva caballera es un sistema axonométrico oblicuo en el que el eje Y (profundidad) no es perpendicular al plano del dibujo, lo que permite proyectar los objetos de forma que una de sus caras principales (habitualmente el alzado, XZ) quede paralela al cuadro y, por tanto, en verdadera magnitud. Los ejes X y Z son, respectivamente, horizontal y vertical en el dibujo, mientras que el eje Y se dibuja inclinado con un ángulo libre, típicamente 30°, 45° o 60°. Esta libertad de ángulo, junto con la ventaja de conservar sin deformación la cara frontal del objeto, la convierte en una perspectiva especialmente cómoda cuando interesa destacar una de las caras del objeto.

Sin embargo, las longitudes paralelas al eje Y se distorsionan al proyectarse en un plano oblicuo: si se tomaran en su valor real, la pieza parecería exageradamente profunda. Por ello, se aplica un coeficiente de reducción en el eje Y, habitualmente 0,5 (reduciendo a la mitad las dimensiones reales) o 0,7, dependiendo del ángulo elegido. Esta reducción proporciona un aspecto más equilibrado y mejora la percepción visual. La perspectiva caballera es particularmente adecuada para representar piezas técnicas con elementos circulares frontales: al conservarse la cara frontal sin deformación, los círculos y circunferencias del alzado se dibujan con compás como verdaderos círculos, mientras que los de caras perpendiculares se representan como elipses. La simplicidad de trazado, la facilidad de medición directa sobre dos ejes y su capacidad de mostrar tres caras a la vez hacen de la caballera una de las perspectivas más utilizadas en manuales técnicos, guías de montaje y dibujos rápidos de ingeniería. Junto con la isométrica, es la perspectiva axonométrica más frecuente en los exámenes EBAU de dibujo técnico.',
'[{"pregunta":"En la perspectiva caballera, la cara frontal del objeto:","opciones":["Se deforma mucho","Se representa en verdadera magnitud, sin deformación","Se ve por detrás","Se elimina"],"correcta":1},{"pregunta":"¿Por qué se aplica un coeficiente de reducción en el eje Y?","opciones":["Por capricho","Porque si no la pieza parecería exageradamente profunda y desproporcionada","Para ahorrar tinta","Por ahorrar tiempo"],"correcta":1},{"pregunta":"La principal ventaja de la caballera es:","opciones":["Ser realista","Mostrar sin deformación la cara frontal, permitiendo dibujar círculos como círculos","Ser simétrica","Permitir medir ángulos"],"correcta":1},{"pregunta":"Los ángulos del eje Y más habituales son:","opciones":["90°","0°","30°, 45° o 60°","120°"],"correcta":2}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{2}', 'Vistas normalizadas y disposiciones',
'Un plano de una pieza suele representarla mediante varias vistas ortogonales, que son proyecciones sobre planos perpendiculares entre sí. Las seis vistas principales son alzado (proyección frontal), planta (vista desde arriba), perfil izquierdo, perfil derecho, vista inferior y vista posterior. Rara vez se usan las seis: habitualmente bastan tres (alzado, planta y un perfil) para describir completamente la pieza, aunque piezas muy simétricas pueden requerir solo dos o incluso una. Las vistas deben colocarse en una disposición estandarizada para que su interpretación sea inequívoca, y aquí existen dos sistemas distintos utilizados internacionalmente: el europeo (primer diedro) y el americano (tercer diedro).

En el sistema europeo (ISO-E), normalizado en Europa y también llamado del primer diedro, cada vista se sitúa al lado opuesto de donde se mira: la planta (vista desde arriba) se coloca debajo del alzado; el perfil izquierdo se coloca a la derecha del alzado; el perfil derecho a la izquierda. Es como si la pieza se apoyara en cada plano y se abatiera sobre el plano del dibujo. En el sistema americano (ISO-A), usado en EE.UU., cada vista se coloca del mismo lado desde donde se mira: la planta arriba, el perfil izquierdo a la izquierda, etc. Para indicar qué sistema se usa se incluye en el cuadro de rotulación un símbolo normalizado (tronco de cono visto en ambos sistemas). Confundir ambos lleva a interpretaciones erróneas. La elección del alzado como vista principal no es arbitraria: debe ser la que mejor muestre la forma característica de la pieza, habitualmente en su posición de uso o fabricación. La disposición de las vistas debe ser económica (no usar más de las estrictamente necesarias) y lógica (sin solapamientos ni omisiones). Estos criterios son esenciales en los ejercicios EBAU, donde se pide tanto dibujar vistas a partir de una perspectiva como reconstruir una perspectiva a partir de vistas normalizadas.',
'[{"pregunta":"En el sistema europeo (ISO-E) de vistas, la planta se coloca:","opciones":["Arriba del alzado","Debajo del alzado","A la derecha","A la izquierda"],"correcta":1},{"pregunta":"¿Cuántas vistas bastan en la mayoría de los casos para describir una pieza?","opciones":["Solo una","Tres (alzado, planta, perfil)","Seis siempre","Dos"],"correcta":1},{"pregunta":"El sistema americano (ISO-A) se diferencia del europeo en que:","opciones":["No usa alzado","Cada vista se coloca del mismo lado desde donde se mira, no del opuesto","No tiene planta","Usa colores"],"correcta":1},{"pregunta":"El alzado debe ser la vista que:","opciones":["Es más grande","Mejor muestre la forma característica de la pieza","Tiene más agujeros","Está de espaldas"],"correcta":1}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{2}', 'Sistema de planos acotados',
'El sistema de planos acotados es una variante del sistema diédrico en la que solo se utiliza un plano de proyección (el plano horizontal) y la cota (altura del punto sobre el plano) se escribe como un número junto a la proyección. Es decir, cada punto se representa por su proyección horizontal con un número que indica su altura, en lugar de usar dos planos separados. Este sistema tiene la ventaja de utilizar solo una representación plana, lo que lo hace especialmente adecuado para obras de ingeniería civil, topografía, planos de carreteras, perfiles de terreno, saneamientos y redes de servicios, donde el elemento fundamental es el plano del terreno.

En el sistema de planos acotados, una recta se representa por su proyección horizontal con las cotas de dos de sus puntos. De ellas puede deducirse la pendiente (cociente entre desnivel y distancia en planta) o el intervalo (distancia en planta entre dos puntos con un desnivel de 1 unidad), parámetros esenciales en diseño viario. Un plano se representa por su recta de máxima pendiente, conocida como línea de máxima pendiente, que es la proyección de la dirección en que más rápidamente varía la altura. La graduación de un plano consiste en trazar sobre él las líneas de nivel (horizontales con cota entera), equivalentes a las curvas de nivel de un mapa topográfico. Las curvas de nivel son la representación estándar del relieve en cartografía: líneas que unen puntos de igual altitud. Su separación indica la pendiente del terreno: líneas muy juntas indican pendientes fuertes, y líneas separadas, pendientes suaves. El sistema se completa con operaciones típicas como cálculo de intersecciones entre planos (rectas de nivel), línea de terreno (intersección entre un plano de obra y el terreno), determinación de desmontes y terraplenes, y estudio de perfiles longitudinales y transversales. Es el sistema de representación fundamental para ingenieros civiles y topógrafos.',
'[{"pregunta":"En el sistema de planos acotados solo se usa:","opciones":["Un plano de proyección (el horizontal) y se indica la cota con un número","Dos planos","Tres planos","Ningún plano"],"correcta":0},{"pregunta":"La línea de máxima pendiente de un plano es:","opciones":["La más horizontal","La dirección en la que más rápidamente varía la altura","Siempre perpendicular al Norte","La diagonal"],"correcta":1},{"pregunta":"Las curvas de nivel de un mapa topográfico unen puntos con:","opciones":["La misma temperatura","La misma altitud","El mismo tamaño","La misma inclinación"],"correcta":1},{"pregunta":"El sistema de planos acotados es especialmente útil en:","opciones":["Piezas mecánicas pequeñas","Ingeniería civil, carreteras, topografía, perfiles de terreno","Electrónica","Diseño de muebles"],"correcta":1}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{2}', 'Transformaciones geométricas en el plano',
'Las transformaciones geométricas son aplicaciones que convierten cada punto del plano en otro punto siguiendo una regla precisa. Las más importantes se clasifican según qué propiedades conservan. Las isometrías (movimientos) conservan distancias y ángulos: incluyen la traslación (desplazamiento de todos los puntos en una misma dirección), la rotación (giro alrededor de un centro por un ángulo fijo) y la simetría (axial respecto a una recta, o central respecto a un punto). Cualquier combinación de isometrías es otra isometría, y se demuestra que cualquier isometría del plano puede descomponerse en a lo sumo tres simetrías axiales, resultado conocido como teorema fundamental de las isometrías.

Las homotecias son un caso especial de semejanzas y consisten en una transformación que, fijado un centro O y una razón k, hace corresponder a cada punto P otro punto P'' sobre la recta OP tal que OP'' = k·OP. Si k > 1 hay ampliación, si 0 < k < 1 hay reducción, y si k es negativo la imagen queda en la semirecta opuesta. Las homotecias conservan ángulos pero multiplican longitudes por |k| y áreas por k². Son fundamentales en la construcción de figuras semejantes, en el escalado de planos y mapas, en la perspectiva cónica y en la óptica (formación de imágenes por lentes). Una semejanza general es la composición de una homotecia con una isometría: conserva ángulos y ratios, pero no longitudes absolutas. Las transformaciones más generales son las afinidades, que conservan el paralelismo y las razones simples pero no los ángulos, y las proyectividades (homologías), que solo conservan la incidencia y la razón doble. Todas estas transformaciones tienen aplicación directa en dibujo técnico para construir figuras semejantes, ampliar o reducir dibujos, estudiar simetrías y abordar los sistemas de representación como instancias de aplicaciones proyectivas. Además son la base matemática de los gráficos por computador, donde las matrices de transformación se usan miles de veces por segundo en tiempo real.',
'[{"pregunta":"Las isometrías son transformaciones que:","opciones":["Cambian las distancias","Conservan distancias y ángulos","Solo cambian el color","No conservan la forma"],"correcta":1},{"pregunta":"Si una homotecia tiene razón k = 2, las áreas de la figura imagen se:","opciones":["Duplican","Cuadruplican (k²)","Reducen","No cambian"],"correcta":1},{"pregunta":"Una semejanza general es:","opciones":["Igual a una homotecia","Composición de una homotecia con una isometría","Una simetría","Una traslación"],"correcta":1},{"pregunta":"En gráficos por computador, las transformaciones se implementan mediante:","opciones":["Hojas de cálculo","Matrices de transformación aplicadas miles de veces por segundo","Textos","Sensores físicos"],"correcta":1}]'::jsonb);

