-- EDUCACIÓN FÍSICA (15 textos)
-- =====================================================

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('ed-fisica', 'bachillerato', '{2}', 'Sistemas energéticos en el ejercicio',
'El músculo esquelético utiliza tres sistemas energéticos diferentes para obtener el ATP necesario durante la contracción, según la intensidad y duración del esfuerzo. El sistema anaeróbico aláctico, o sistema de los fosfágenos, utiliza los depósitos de ATP y fosfocreatina (PCr) presentes en el propio músculo. Es el más rápido en disponibilidad (menos de un segundo) pero también el más limitado en capacidad: se agota en aproximadamente 10-15 segundos de esfuerzo máximo. Es el sistema dominante en esfuerzos explosivos como lanzamientos, saltos, sprints cortos o levantamientos de peso.

El sistema anaeróbico láctico, o glucolítico anaeróbico, degrada la glucosa hasta piruvato, que en ausencia de oxígeno suficiente se convierte en lactato. Proporciona energía rápidamente pero no tanto como los fosfágenos, con una capacidad mayor aunque limitada: es el sistema dominante entre 15 y 60 segundos aproximadamente, en pruebas como 400 metros lisos, 100 metros en natación o ejercicios intermitentes de alta intensidad. La acumulación de lactato y protones en el músculo contribuye a la fatiga. El sistema aeróbico u oxidativo oxida completamente la glucosa y, en esfuerzos más prolongados, también los lípidos y proteínas en la mitocondria, produciendo hasta 30-32 ATP por molécula de glucosa frente a los 2 ATP de la vía anaeróbica. Es el sistema más rentable energéticamente pero también el más lento en activarse (requiere varios minutos para alcanzar su máximo rendimiento); es el dominante en esfuerzos superiores a unos pocos minutos. En la práctica, los tres sistemas no funcionan aisladamente: operan simultáneamente, con distinto grado de predominio según la intensidad y la duración. El entrenamiento específico para cada deporte debe estimular preferentemente los sistemas energéticos implicados en su modalidad.',
'[{"pregunta":"El sistema anaeróbico aláctico se basa en:","opciones":["La glucosa","El ATP y la fosfocreatina musculares","La oxidación de grasas","Los aminoácidos"],"correcta":1},{"pregunta":"¿Qué sistema predomina en un esfuerzo de 400 metros lisos?","opciones":["Anaeróbico aláctico","Anaeróbico láctico","Aeróbico","Ninguno"],"correcta":1},{"pregunta":"El sistema aeróbico produce por glucosa:","opciones":["2 ATP","Hasta 30-32 ATP","Infinitos ATP","0 ATP"],"correcta":1},{"pregunta":"Los tres sistemas energéticos:","opciones":["Funcionan de manera aislada","Operan simultáneamente con distinto predominio según intensidad y duración","Solo actúa uno a la vez","No coinciden nunca"],"correcta":1}]'::jsonb),

('ed-fisica', 'bachillerato', '{2}', 'Umbrales anaeróbico y ventilatorio',
'Durante el ejercicio incremental, el consumo de oxígeno y la producción de lactato aumentan progresivamente, pero no lo hacen de forma lineal. Existen puntos críticos llamados umbrales, que marcan cambios fisiológicos importantes y son marcadores fundamentales del rendimiento deportivo y de la planificación del entrenamiento. El primer umbral ventilatorio (VT1) corresponde a la intensidad a partir de la cual la ventilación pulmonar empieza a aumentar desproporcionadamente respecto al consumo de oxígeno, debido al inicio de la producción significativa de lactato. Coincide aproximadamente con el umbral aeróbico o umbral de lactato de 2 mmol/L.

El segundo umbral, llamado umbral anaeróbico o umbral láctico (VT2, OBLA, MLSS), corresponde a la máxima intensidad que puede sostenerse sin que el lactato acumulado siga creciendo indefinidamente. Por encima de él, el lactato se produce más rápidamente que se elimina y el esfuerzo no puede mantenerse mucho tiempo. Suele coincidir con una concentración de lactato sanguíneo de 4 mmol/L, aunque varía entre individuos. Por debajo de este umbral, el ejercicio es sostenible durante largos periodos (hasta varias horas) porque el organismo puede mantener el equilibrio metabólico. El umbral anaeróbico es un marcador mucho mejor del rendimiento aeróbico que el VO2 máximo, porque indica el porcentaje de VO2max que el atleta es capaz de sostener; los corredores de maratón de élite lo tienen al 85-90 % de su VO2max. El entrenamiento específico en torno a los umbrales (entrenamiento de "fondo extensivo" por debajo del VT1, "tempo" entre umbrales y "series interválicas" por encima) es la base del entrenamiento científico del deporte de resistencia. La determinación de umbrales requiere pruebas de laboratorio con análisis de gases espirados y lactato sanguíneo en incrementos controlados de carga.',
'[{"pregunta":"El umbral anaeróbico marca:","opciones":["El inicio del ejercicio","La máxima intensidad sostenible sin acumulación indefinida de lactato","La máxima potencia","El cansancio absoluto"],"correcta":1},{"pregunta":"El umbral anaeróbico suele coincidir con:","opciones":["1 mmol/L de lactato","4 mmol/L de lactato","10 mmol/L","Siempre el VO2max"],"correcta":1},{"pregunta":"Los maratonianos de élite compiten aproximadamente al:","opciones":["50 % del VO2max","85-90 % del VO2max","100 %","25 %"],"correcta":1},{"pregunta":"¿Por qué el umbral anaeróbico predice mejor el rendimiento que el VO2max?","opciones":["Porque es más fácil de medir","Porque indica qué porcentaje de VO2max puede sostenerse durante una prueba larga","Por ser universal","Por tener una unidad más simple"],"correcta":1}]'::jsonb),

('ed-fisica', 'bachillerato', '{2}', 'Nutrición deportiva: macronutrientes',
'La alimentación del deportista debe adaptarse al gasto energético y al tipo de esfuerzo realizado. Los tres macronutrientes (hidratos de carbono, grasas y proteínas) cumplen funciones distintas y complementarias. Los hidratos de carbono son el combustible preferido del músculo durante el ejercicio de intensidad media-alta, almacenándose como glucógeno en hígado y músculo. Un deportista de fondo puede almacenar de 400 a 600 g de glucógeno, suficientes para 90-120 minutos de esfuerzo intenso. Se recomiendan entre 5 y 10 g/kg/día según intensidad y volumen de entrenamiento, preferentemente de fuentes complejas (cereales integrales, legumbres, tubérculos) salvo durante y justo después del ejercicio, cuando los de absorción rápida (frutas, bebidas deportivas, geles) son más apropiados para reponer el glucógeno.

Las grasas son el combustible principal en reposo y en esfuerzos de baja intensidad y larga duración. Su reserva corporal es prácticamente inagotable a efectos prácticos, pero su oxidación es más lenta. Las recomendaciones están en torno al 20-35 % del aporte energético, priorizando las insaturadas (aceite de oliva, frutos secos, pescado azul) y limitando las saturadas y trans. Las proteínas desempeñan papel estructural (miofibrillas, enzimas, inmunoglobulinas) y sirven para reparar y construir masa muscular, pero también pueden oxidarse como combustible en situaciones de baja disponibilidad de glucógeno. Las necesidades de un deportista son de 1,2 a 2 g/kg/día (frente a los 0,8 de una persona sedentaria), con mayores requerimientos en deportes de fuerza que en resistencia. La ventana anabólica postejercicio (primeras 1-2 horas) es especialmente favorable para reponer glucógeno y aportar proteínas que estimulen la síntesis proteica. La hidratación es esencial: una pérdida del 2 % del peso corporal por deshidratación ya disminuye el rendimiento significativamente, y por encima del 5 % puede comprometer la salud. En ejercicios prolongados en calor, se debe reponer agua y electrolitos perdidos por el sudor.',
'[{"pregunta":"Los hidratos de carbono se almacenan en músculo e hígado como:","opciones":["Grasa","Glucógeno","Aminoácidos","Proteína"],"correcta":1},{"pregunta":"Las necesidades proteicas de un deportista son:","opciones":["0,5 g/kg/día","1,2 a 2 g/kg/día según el deporte","10 g/kg/día","Ninguna"],"correcta":1},{"pregunta":"La ventana anabólica postejercicio favorece:","opciones":["La pérdida de peso","La reposición de glucógeno y la síntesis proteica","El ayuno","El descanso absoluto"],"correcta":1},{"pregunta":"Una deshidratación del 2 % del peso corporal:","opciones":["No tiene efectos","Ya reduce el rendimiento de forma significativa","Solo afecta al sueño","Es imposible"],"correcta":1}]'::jsonb),

('ed-fisica', 'bachillerato', '{2}', 'Principios del entrenamiento deportivo',
'El entrenamiento deportivo eficaz se fundamenta en un conjunto de principios biológicos comunes a todas las disciplinas. El primero es el principio de sobrecarga o de adaptación: el organismo solo se adapta y mejora si recibe estímulos suficientemente superiores a los habituales. Un estímulo demasiado suave no provoca adaptaciones; uno demasiado intenso causa sobreentrenamiento o lesión. Ligado a éste está el principio de progresión, según el cual la carga debe incrementarse de forma paulatina a medida que el organismo se adapta, en cuanto a volumen (cantidad de trabajo), intensidad (grado de esfuerzo) o densidad (relación trabajo-descanso).

El principio de especificidad establece que las adaptaciones son altamente específicas respecto a las características del estímulo: un corredor mejora corriendo, no nadando, aunque ambos sean ejercicios aeróbicos. El entrenamiento debe simular las demandas reales de la competición en gesto técnico, sistemas energéticos, musculatura implicada e incluso contexto psicológico. El principio de individualización recuerda que cada deportista es único (edad, sexo, nivel, genética, historial de lesiones) y el entrenamiento debe personalizarse. El principio de recuperación reconoce que las adaptaciones no ocurren durante el estímulo sino durante la fase de descanso posterior, según el modelo de supercompensación: después del entrenamiento, el organismo no solo recupera su nivel previo sino que lo supera temporalmente, quedando preparado para soportar una carga mayor. Un nuevo estímulo debe aplicarse en este pico para maximizar la mejora; si llega demasiado pronto, se acumula fatiga; si llega demasiado tarde, se pierde la ganancia. Finalmente, el principio de continuidad establece que las adaptaciones se pierden con la inactividad (principio de reversibilidad o "úsalo o piérdelo"): un mes sin entrenar supone retrocesos significativos, especialmente en resistencia. La correcta aplicación integrada de todos estos principios es lo que diferencia un entrenamiento profesional de uno improvisado.',
'[{"pregunta":"El principio de sobrecarga afirma que:","opciones":["Hay que entrenar menos","Se necesita un estímulo suficientemente superior al habitual para provocar adaptaciones","Todos los entrenamientos son iguales","El descanso es lo más importante"],"correcta":1},{"pregunta":"La supercompensación describe:","opciones":["Un aumento temporal del rendimiento sobre el nivel previo tras un buen descanso","La pérdida de masa muscular","El cansancio","El calentamiento"],"correcta":0},{"pregunta":"El principio de especificidad implica que:","opciones":["Cualquier ejercicio vale","Las adaptaciones son específicas al tipo de estímulo y gesto entrenado","El entrenamiento debe ser siempre el mismo","No hay que especializarse"],"correcta":1},{"pregunta":"El principio de reversibilidad significa que:","opciones":["Las adaptaciones se conservan para siempre","Las adaptaciones se pierden con la inactividad prolongada","Se puede entrenar al revés","Solo vale para deportes colectivos"],"correcta":1}]'::jsonb),

('ed-fisica', 'bachillerato', '{2}', 'Psicología deportiva: motivación y concentración',
'La psicología deportiva estudia los factores mentales que influyen en el rendimiento, el bienestar y la adherencia a la práctica deportiva. Uno de los temas centrales es la motivación, entendida como la razón que lleva a una persona a iniciar, mantener o abandonar una conducta. La teoría de la autodeterminación (Deci y Ryan) distingue entre motivación intrínseca (cuando uno hace algo por el placer que le proporciona la propia actividad) y motivación extrínseca (cuando se hace por incentivos externos como premios, dinero o el reconocimiento). La motivación intrínseca está asociada con mayor persistencia, disfrute, creatividad y menor abandono; la extrínseca puede ser eficaz a corto plazo pero es menos estable.

El establecimiento de metas es una herramienta psicológica muy eficaz para mantener la motivación. Las metas deben ser SMART: específicas (Specific), medibles (Measurable), alcanzables (Achievable), relevantes (Relevant) y con plazo (Time-bound). Se distinguen metas de resultado (ganar un campeonato), de rendimiento (mejorar un tiempo propio) y de proceso (ejecutar un gesto técnico correctamente); las dos últimas son preferibles porque dependen del propio deportista y no de rivales. Otro factor clave es la concentración o atención, la capacidad de mantener el foco en estímulos relevantes ignorando los distractores. Los deportistas de élite desarrollan rutinas precompetitivas que facilitan entrar en el "estado de flujo" (Csikszentmihalyi), caracterizado por concentración plena, sensación de control, distorsión del tiempo y rendimiento óptimo. El control emocional es igualmente importante: la ansiedad precompetitiva excesiva deteriora el rendimiento (ley de Yerkes-Dodson: el rendimiento es óptimo a un nivel intermedio de activación), mientras que la baja motivación o la apatía también lo reducen. Técnicas como la respiración diafragmática, la relajación muscular progresiva, la visualización mental y el diálogo interno positivo permiten regular estos estados. La psicología deportiva moderna integra todas estas herramientas en la preparación del deportista junto al entrenamiento físico, técnico y táctico.',
'[{"pregunta":"La motivación intrínseca se caracteriza por:","opciones":["Buscar recompensas externas","Hacer algo por el placer que proporciona la propia actividad","Obediencia","Competir con otros"],"correcta":1},{"pregunta":"Las metas SMART son:","opciones":["Específicas, medibles, alcanzables, relevantes y con plazo","Solo numéricas","Siempre a largo plazo","Informales"],"correcta":0},{"pregunta":"La ley de Yerkes-Dodson afirma que:","opciones":["A más ansiedad, mejor rendimiento","El rendimiento es óptimo a un nivel intermedio de activación","El rendimiento no depende del estado emocional","La ansiedad siempre es positiva"],"correcta":1},{"pregunta":"El estado de flujo se caracteriza por:","opciones":["Confusión","Concentración plena, sensación de control y rendimiento óptimo","Miedo","Hiperactividad"],"correcta":1}]'::jsonb),

('ed-fisica', 'bachillerato', '{2}', 'Biomecánica del salto y la carrera',
'La biomecánica aplica las leyes de la física al estudio del movimiento humano para optimizar el rendimiento y prevenir lesiones. En la carrera, el centro de gravedad describe un movimiento ondulante con fases de apoyo (un pie en contacto con el suelo) y fases de vuelo (ambos pies en el aire). En cada apoyo, el corredor recibe una fuerza de reacción del suelo que tiene componentes verticales (para contrarrestar la gravedad y reaccionar al impulso descendente) y horizontales (una primera componente de frenado al contactar, y una segunda de propulsión al empujar hacia atrás). La eficiencia de un corredor depende de factores como la frecuencia y amplitud de zancada, el ángulo de ataque del pie, la colocación del tronco y el aprovechamiento del ciclo estiramiento-acortamiento muscular, que permite recuperar parte de la energía elástica almacenada en tendones y fascias durante la fase excéntrica.

En los saltos verticales, el principio fundamental es el impulso: la variación del momento lineal es igual a la integral de la fuerza aplicada durante el tiempo de contacto con el suelo. Maximizar la altura alcanzada requiere generar una gran fuerza durante un intervalo suficiente (los dos factores son necesarios). La fase excéntrica previa (flexión profunda de rodillas) almacena energía elástica en los elementos conectivos y activa el reflejo miotático, aumentando la fuerza de la contracción concéntrica posterior. Este es el principio del contra-movimiento: un salto con flexión previa salta más que un salto puramente estático, y un salto con caída previa (drop jump) todavía más. En los saltos horizontales, además hay que optimizar el ángulo de despegue, teóricamente cercano a 45° para maximizar el alcance parabólico, aunque en la práctica los saltadores lo reducen porque generan mejor potencia en ángulos más bajos. El análisis biomecánico moderno utiliza plataformas de fuerza, sistemas de captura de movimiento con cámaras de alta velocidad y electromiografía para cuantificar todos estos parámetros y guiar la mejora técnica.',
'[{"pregunta":"La fuerza de reacción del suelo durante la carrera tiene:","opciones":["Solo componente vertical","Componentes vertical y horizontales (frenado y propulsión)","Solo componente horizontal","No existe"],"correcta":1},{"pregunta":"El contra-movimiento en un salto vertical permite:","opciones":["Reducir la altura","Aumentar la altura al almacenar energía elástica y activar el reflejo miotático","No es útil","Evitar lesiones únicamente"],"correcta":1},{"pregunta":"En un salto horizontal, el ángulo óptimo teórico de despegue es:","opciones":["0°","45°","90°","120°"],"correcta":1},{"pregunta":"La biomecánica moderna mide el movimiento con:","opciones":["Solo la vista","Plataformas de fuerza, captura óptica y electromiografía","Cronómetro","Cinta métrica únicamente"],"correcta":1}]'::jsonb),

('ed-fisica', 'bachillerato', '{2}', 'Fisiología cardiovascular en el ejercicio',
'El sistema cardiovascular se adapta rápidamente a las demandas del ejercicio para aumentar el aporte de oxígeno y nutrientes a los músculos activos. La respuesta más inmediata es el aumento del gasto cardíaco (Q), que es el volumen de sangre bombeado por el corazón por unidad de tiempo. Q = FC·VS, donde FC es la frecuencia cardíaca (latidos por minuto) y VS es el volumen sistólico (mililitros expulsados en cada latido). En reposo, Q es de unos 5 L/min; durante ejercicio máximo en sedentarios puede alcanzar 20 L/min y en deportistas de élite 40 L/min. Tanto la frecuencia como el volumen sistólico aumentan con el esfuerzo, pero el volumen sistólico llega a un plateau en torno al 50 % del VO2max, a partir del cual los aumentos de gasto cardíaco se deben casi exclusivamente al aumento de frecuencia.

El entrenamiento de resistencia produce adaptaciones notables en el sistema cardiovascular. La más característica es la hipertrofia cardíaca excéntrica: las cavidades del ventrículo izquierdo se dilatan, permitiendo albergar más sangre en diástole. Esto aumenta el volumen sistólico en reposo y en ejercicio, reduciendo la frecuencia cardíaca necesaria para bombear el mismo gasto. Los deportistas entrenados tienen frecuencias cardíacas en reposo mucho más bajas que las personas sedentarias (40-50 latidos/min frente a 70-80), fenómeno conocido como bradicardia del deportista. La frecuencia cardíaca máxima (aproximadamente 220 − edad, con gran variabilidad individual) no suele cambiar con el entrenamiento. Otras adaptaciones son el aumento del volumen plasmático, la capilarización de los músculos entrenados (mayor densidad capilar mejora la entrega de oxígeno), el aumento del número de eritrocitos y hemoglobina, y el mejor funcionamiento periférico de los músculos para extraer oxígeno. Estas adaptaciones explican el aumento progresivo del VO2max con el entrenamiento y la mejora del rendimiento en pruebas de resistencia.',
'[{"pregunta":"El gasto cardíaco es:","opciones":["La FC","FC × volumen sistólico","Solo el volumen sistólico","Latidos por día"],"correcta":1},{"pregunta":"La bradicardia del deportista consiste en:","opciones":["Ritmo cardíaco irregular","Frecuencia cardíaca en reposo inferior a la habitual por entrenamiento","Ausencia de pulso","Taquicardia"],"correcta":1},{"pregunta":"Una adaptación típica del corazón al entrenamiento de resistencia es:","opciones":["Reducción de tamaño","Hipertrofia excéntrica del ventrículo izquierdo","Arritmias","Disminución del gasto"],"correcta":1},{"pregunta":"La frecuencia cardíaca máxima:","opciones":["Crece con el entrenamiento","No suele cambiar significativamente con el entrenamiento y depende de la edad","Es 300 lpm","Siempre es 100 lpm"],"correcta":1}]'::jsonb),

('ed-fisica', 'bachillerato', '{2}', 'Tipos de fibras musculares',
'El músculo esquelético está formado por dos tipos principales de fibras con propiedades bioquímicas y funcionales muy distintas. Las fibras tipo I, o lentas oxidativas, son fibras de pequeño calibre, muy ricas en mitocondrias, mioglobina (de ahí su color rojo oscuro) y capilares. Su metabolismo es fundamentalmente aeróbico, resisten muy bien la fatiga y están especializadas en esfuerzos prolongados de baja o media intensidad. Son predominantes en los músculos posturales (sóleo, paraspinales) que deben mantenerse activos de forma sostenida. Los corredores de fondo y ciclistas de larga distancia presentan una elevada proporción de fibras tipo I en los músculos relevantes para su deporte.

Las fibras tipo II, o rápidas, tienen un metabolismo predominantemente anaeróbico (aunque existe un subtipo intermedio IIa con cierta capacidad aeróbica). Son fibras de gran calibre, pobres en mitocondrias, ricas en glucógeno y enzimas glucolíticas, con mayor velocidad de contracción y mayor fuerza pero menor resistencia a la fatiga. Son las responsables de los movimientos explosivos y potentes. Los velocistas, saltadores y levantadores de pesas presentan una elevada proporción de fibras tipo II. La distribución relativa de los dos tipos en cada músculo está determinada genéticamente en gran medida y solo se modifica parcialmente con el entrenamiento: el entrenamiento de resistencia puede transformar fibras IIx en IIa y aumentar el contenido oxidativo de todas las fibras, y el entrenamiento de fuerza hipertrofia sobre todo las IIa, pero no se puede convertir masivamente un corredor de fondo en velocista ni viceversa. El conocimiento del perfil muscular es útil para orientar a un deportista hacia la disciplina en la que puede destacar más y para personalizar su entrenamiento. El análisis se realiza por biopsia muscular y tinción histoquímica, o más recientemente por métodos inmunohistoquímicos. Sin embargo, para la mayoría de los deportistas, el trabajo específico de su deporte es más importante que la composición genética.',
'[{"pregunta":"Las fibras tipo I se caracterizan por ser:","opciones":["Rápidas y fatigables","Lentas, oxidativas, muy resistentes a la fatiga","Las de los velocistas","Rojas pero rápidas"],"correcta":1},{"pregunta":"Los velocistas suelen tener una elevada proporción de:","opciones":["Fibras tipo I","Fibras tipo II","Fibras cardíacas","Ninguno"],"correcta":1},{"pregunta":"La distribución entre fibras I y II:","opciones":["Es totalmente modificable","Está determinada en gran parte genéticamente y solo se modifica parcialmente","Cambia cada semana","No existe"],"correcta":1},{"pregunta":"El entrenamiento de resistencia puede:","opciones":["Convertir todo tipo II en tipo I","Transformar fibras IIx en IIa y mejorar el metabolismo oxidativo","No tener efecto","Eliminar las fibras II"],"correcta":1}]'::jsonb),

('ed-fisica', 'bachillerato', '{2}', 'Prevención de lesiones deportivas',
'Las lesiones deportivas son un problema habitual que afecta al rendimiento y al bienestar de los practicantes. Pueden clasificarse por mecanismo de producción en agudas (traumáticas, como esguinces, fracturas o roturas musculares tras un impacto o un gesto brusco) y crónicas (por sobrecarga, como tendinopatías, fracturas de estrés o periostitis, causadas por microtraumatismos repetidos que no llegan a curarse adecuadamente). Los factores de riesgo se dividen en intrínsecos (edad, sexo, condición física, desequilibrios musculares, falta de flexibilidad, biomecánica individual) y extrínsecos (tipo de superficie, calzado, equipamiento, condiciones meteorológicas, carga de entrenamiento).

La prevención se basa en un conjunto de medidas estructuradas. El calentamiento adecuado aumenta progresivamente la temperatura corporal, moviliza el cardiovascular y el sistema nervioso, activa los músculos implicados y prepara los tejidos conectivos. Debe incluir ejercicios dinámicos específicos del deporte a practicar. El trabajo de fuerza, especialmente en cadenas funcionales y en zonas frecuentemente lesionadas (core, isquiotibiales, aductores, manguito rotador), reduce sustancialmente el riesgo de lesión. El entrenamiento neuromuscular y propioceptivo (equilibrio, superficies inestables, plyometría controlada) mejora la estabilidad articular y la coordinación intermuscular. La progresión gradual de la carga es crucial: aumentos superiores al 10 % semanal en el volumen o la intensidad están asociados con más lesiones. El descanso adecuado entre sesiones es igualmente importante, pues las lesiones por sobreuso reflejan la incapacidad del tejido para adaptarse al ritmo de carga impuesto. Otras medidas son usar calzado y equipamiento adecuado, corregir errores técnicos, respetar el gesto técnico, mantener una buena hidratación y nutrición, y consultar precozmente a profesionales ante los primeros síntomas. Protocolos como el FIFA 11+ en fútbol o los ejercicios excéntricos de Askling para isquiotibiales son ejemplos de estrategias con evidencia científica que reducen drásticamente la incidencia de lesiones.',
'[{"pregunta":"Una tendinopatía crónica es una lesión:","opciones":["Por traumatismo único","Por sobreuso con microtraumatismos repetidos","Viral","Psicológica"],"correcta":1},{"pregunta":"El aumento semanal de carga de entrenamiento asociado con menos lesiones es:","opciones":["Superior al 50 %","No superior al 10 % aproximadamente","No importa","Debe ser cero"],"correcta":1},{"pregunta":"Un calentamiento adecuado debe incluir:","opciones":["Solo estiramientos estáticos","Movilización dinámica específica del deporte","30 minutos de siesta","Una carrera máxima"],"correcta":1},{"pregunta":"El programa FIFA 11+ es un ejemplo de:","opciones":["Táctica ofensiva","Protocolo de prevención de lesiones con evidencia científica","Norma arbitral","Método de nutrición"],"correcta":1}]'::jsonb),

('ed-fisica', 'bachillerato', '{2}', 'Capacidades físicas básicas',
'Las capacidades físicas básicas son los componentes fundamentales del rendimiento motor y se clasifican tradicionalmente en cuatro: resistencia, fuerza, velocidad y flexibilidad. La resistencia es la capacidad de mantener un esfuerzo durante el mayor tiempo posible. Se distingue entre resistencia aeróbica (esfuerzos de baja y media intensidad sostenidos con suficiente oxigenación; base del entrenamiento de fondo) y anaeróbica (esfuerzos más intensos en los que se produce déficit de oxígeno). Se mejora con entrenamiento continuo, interválico o fartlek, y su indicador máximo es el VO2max.

La fuerza es la capacidad de vencer o soportar una resistencia mediante la contracción muscular. Puede ser máxima (vencer la mayor resistencia posible en una sola repetición), explosiva (generar la mayor aceleración posible, relacionada con la potencia) o de resistencia (mantener una contracción durante mucho tiempo). Se entrena con pesas, máquinas, trabajo con el propio cuerpo, bandas elásticas o entrenamiento funcional. La velocidad es la capacidad de ejecutar un movimiento o desplazarse en el menor tiempo posible; depende de factores nerviosos (velocidad de reacción, frecuencia de impulsos), musculares (tipos de fibras) y biomecánicos. La velocidad de reacción, de aceleración y la velocidad máxima son componentes distintos. La flexibilidad es el rango de movimiento articular disponible, determinado por la elasticidad muscular y conectiva y por la estructura ósea y cartilaginosa. Se entrena mediante estiramientos estáticos (mantener posición), dinámicos (movimientos activos amplios), PNF (contracción-relajación alternadas) y yoga o pilates. Estas cuatro capacidades interactúan entre sí y con otras como la coordinación, el equilibrio o la agilidad, dando lugar a capacidades complejas específicas de cada deporte. La condición física general incluye todas ellas en dosis equilibradas, mientras que la preparación específica para competición enfatiza las predominantes en la disciplina.',
'[{"pregunta":"El indicador máximo de la resistencia aeróbica es:","opciones":["La fuerza","El VO2max","La flexibilidad","La velocidad máxima"],"correcta":1},{"pregunta":"La fuerza explosiva se asocia con:","opciones":["La lentitud","La potencia, es decir la capacidad de generar fuerza rápidamente","La resistencia aeróbica","El peso corporal"],"correcta":1},{"pregunta":"El PNF (facilitación neuromuscular propioceptiva) es un método para entrenar:","opciones":["Fuerza máxima","Flexibilidad, con contracciones y relajaciones alternadas","Resistencia","Velocidad de reacción"],"correcta":1},{"pregunta":"La velocidad depende fundamentalmente de:","opciones":["Solo la masa muscular","Factores nerviosos, musculares y biomecánicos combinados","El VO2max","La flexibilidad"],"correcta":1}]'::jsonb),

('ed-fisica', 'bachillerato', '{2}', 'Ayudas ergogénicas y dopaje',
'Las ayudas ergogénicas son sustancias o técnicas cuyo objetivo es mejorar el rendimiento deportivo. Se clasifican en nutricionales (creatina, cafeína, beta-alanina, bicarbonato, nitratos), farmacológicas, psicológicas, biomecánicas (materiales, calzado, aerodinámica) y fisiológicas (altitud, cámaras hipóxicas). Algunas son legales y ampliamente usadas con respaldo científico: la cafeína a dosis de 3-6 mg/kg antes del ejercicio mejora rendimiento tanto de fuerza como de resistencia; la creatina monohidrato aumenta la capacidad de producción de ATP en esfuerzos explosivos y la masa muscular; el bicarbonato sódico tampona la acidez en esfuerzos anaeróbicos intensos; los nitratos del zumo de remolacha mejoran la eficiencia mitocondrial. Estos productos están incluidos en la lista de la Agencia Mundial Antidopaje (WADA) como permitidos.

El dopaje, en cambio, consiste en el uso de sustancias o métodos prohibidos. La WADA publica anualmente la lista de sustancias y métodos prohibidos, que incluye agentes anabolizantes (testosterona, nandrolona), hormonas peptídicas y factores de crecimiento (EPO, hormona del crecimiento), beta-agonistas, moduladores hormonales, diuréticos, estimulantes (anfetaminas, cocaína), narcóticos, cannabinoides, glucocorticoides en ciertas vías de administración y métodos como transfusiones sanguíneas, manipulación genética y dopaje génico. El dopaje se combate mediante controles sanguíneos y de orina, tanto en competición como fuera de ella, y mediante el pasaporte biológico del deportista, que monitoriza parámetros a lo largo del tiempo para detectar variaciones sospechosas. Los motivos para prohibir el dopaje son tres: preservar la igualdad y el juego limpio entre deportistas, proteger la salud de los propios atletas (el uso no médico de estas sustancias causa efectos adversos graves, a veces letales) y proteger el espíritu del deporte como ejemplo social y educativo. Casos como el del ciclismo en los años 90 o el de la atletismo ruso en 2015 muestran que el problema va más allá de fallos individuales y puede afectar a equipos o federaciones enteras.',
'[{"pregunta":"La cafeína como ayuda ergogénica:","opciones":["Está prohibida","Está permitida y mejora rendimiento con evidencia científica","Es un placebo","No tiene efectos"],"correcta":1},{"pregunta":"El pasaporte biológico del deportista:","opciones":["Es un carnet","Monitoriza parámetros sanguíneos del deportista a lo largo del tiempo para detectar anomalías","Es obligatorio para viajar","No existe"],"correcta":1},{"pregunta":"El dopaje con EPO consigue:","opciones":["Aumentar la fuerza","Incrementar el número de glóbulos rojos y la capacidad aeróbica","Mejorar la flexibilidad","Reducir el peso"],"correcta":1},{"pregunta":"¿Cuál es una razón para prohibir el dopaje?","opciones":["Es caro","Atenta contra el juego limpio y la salud del deportista","Es ineficaz","No mejora el rendimiento"],"correcta":1}]'::jsonb),

('ed-fisica', 'bachillerato', '{2}', 'VO2máximo: concepto y entrenamiento',
'El consumo máximo de oxígeno (VO2max) es la cantidad máxima de oxígeno que el organismo puede captar, transportar y consumir por unidad de tiempo durante un ejercicio de intensidad creciente hasta el agotamiento. Se expresa en valores absolutos (litros/minuto) o relativos al peso corporal (ml/kg/min), siendo los relativos más útiles para comparar deportistas. Es considerado el principal indicador fisiológico de la capacidad aeróbica, aunque en pruebas muy prolongadas el umbral anaeróbico y la economía de carrera son predictores incluso mejores del rendimiento. Los valores oscilan entre 30-40 ml/kg/min en personas sedentarias, 50-60 en deportistas entrenados y pueden superar 80-90 en deportistas de élite de resistencia. Los esquiadores de fondo y ciclistas profesionales presentan los valores más altos jamás registrados, cercanos a 95 ml/kg/min.

El VO2max depende tanto de factores centrales (capacidad del corazón y de los pulmones para entregar oxígeno) como de factores periféricos (capacidad del músculo para extraerlo y utilizarlo). Mathematicamente, la ecuación de Fick expresa esta realidad: VO2 = Q · (CaO2 − CvO2), donde Q es el gasto cardíaco, CaO2 el contenido arterial de oxígeno y CvO2 el contenido venoso. El VO2max puede incrementarse con entrenamiento específico en un 10-20 % desde el estado inicial en personas no entrenadas, pero tiene un techo fundamentalmente determinado por la genética: el talento para la resistencia es en gran parte heredado. Los métodos más eficaces para mejorar el VO2max son los entrenamientos interválicos de alta intensidad (HIIT) a intensidades cercanas o superiores al 95 % del VO2max, alternadas con descansos activos. Intervalos clásicos de 4×4 minutos al 90 % de la FCmax con 3 minutos de recuperación (método Norwegian) son muy eficaces. El entrenamiento en altitud moderada estimula la producción endógena de EPO, aumentando el hematocrito y, con él, el transporte de oxígeno, aunque el efecto es transitorio al retornar al nivel del mar.',
'[{"pregunta":"El VO2max se expresa en:","opciones":["Segundos","Ml/kg/min o L/min","Kilómetros","Grados"],"correcta":1},{"pregunta":"La ecuación de Fick VO2 = Q·(CaO2 − CvO2) indica que el VO2 depende de:","opciones":["Solo el corazón","Factores centrales (gasto cardíaco) y periféricos (extracción de O2)","Solo los músculos","Únicamente la genética"],"correcta":1},{"pregunta":"Los entrenamientos HIIT se realizan a intensidades:","opciones":["Muy bajas","Cercanas al VO2max (90-95 %) con recuperaciones activas","Constantes del 50 %","Mínimas"],"correcta":1},{"pregunta":"Entrenar en altitud moderada mejora el rendimiento porque:","opciones":["Hace menos calor","Estimula la producción endógena de EPO y aumenta el transporte de oxígeno","No tiene ningún efecto","Aumenta la fuerza muscular"],"correcta":1}]'::jsonb),

('ed-fisica', 'bachillerato', '{2}', 'La planificación del entrenamiento: periodización',
'La periodización es la organización sistemática del entrenamiento a lo largo del tiempo para optimizar el rendimiento en los momentos clave del calendario competitivo. Su formulación clásica, atribuida al entrenador soviético Lev Matveyev en los años 60, divide el año deportivo en macrociclos (temporadas completas), mesociclos (bloques de varias semanas con orientación específica) y microciclos (semanas individuales de entrenamiento). Un macrociclo típico comprende una fase preparatoria general (volumen alto, intensidad baja, orientación aeróbica y fuerza general), una fase preparatoria específica (transición hacia los gestos técnicos del deporte y cargas más específicas), una fase competitiva (intensidades máximas, reducción del volumen, tapering antes de las competiciones clave) y una fase de transición o descarga (descanso activo para recuperarse y evitar el sobreentrenamiento).

La periodización tradicional de Matveyev, con su progresión única de volumen a intensidad, funcionó bien cuando el calendario tenía pocas competiciones importantes al año. Hoy los deportistas compiten muchas veces y necesitan mantener alto rendimiento durante periodos prolongados, lo que ha dado lugar a modelos más sofisticados. La periodización por bloques, propuesta por Verkhoshansky e Issurin, concentra en cada mesociclo el entrenamiento de unas pocas capacidades compatibles entre sí (bloques de acumulación, transformación y realización), explotando el efecto residual de las adaptaciones conseguidas. La periodización ondulante introduce variaciones diarias o semanales en volumen e intensidad, particularmente útil en deportes con demandas variadas. El tapering es la fase de reducción progresiva de la carga (típicamente 50-70 % del volumen habitual) en las dos o tres semanas previas a una competición importante, lo que permite recuperarse de la fatiga acumulada y entrar en supercompensación, maximizando el rendimiento. Una buena planificación debe respetar los principios de entrenamiento, tener en cuenta el calendario real del deportista y ser flexible para adaptarse a imprevistos como enfermedades o lesiones.',
'[{"pregunta":"¿Quién formuló la periodización clásica?","opciones":["Cooper","Lev Matveyev","Lance Armstrong","Yerkes"],"correcta":1},{"pregunta":"La fase de transición en un macrociclo tradicional tiene como objetivo:","opciones":["Competir","Recuperarse activamente y evitar el sobreentrenamiento","Aumentar al máximo la fuerza","Hacer pruebas médicas"],"correcta":1},{"pregunta":"La periodización por bloques se caracteriza por:","opciones":["Hacer lo mismo todo el año","Concentrar el trabajo de unas pocas capacidades compatibles en cada bloque","No variar nunca","Eliminar la técnica"],"correcta":1},{"pregunta":"El tapering consiste en:","opciones":["Aumentar al máximo la carga antes de competir","Reducir progresivamente la carga antes de una competición importante","Entrenar doble","Descansar totalmente"],"correcta":1}]'::jsonb),

('ed-fisica', 'bachillerato', '{2}', 'Obesidad, sedentarismo y salud pública',
'El sedentarismo y la obesidad son dos de los principales problemas de salud pública del siglo XXI. Según la OMS, la inactividad física es responsable de aproximadamente 3,2 millones de muertes anuales en el mundo y es el cuarto factor de riesgo de mortalidad global. El sedentarismo se define como pasar la mayor parte del tiempo sentado o recostado, con gasto energético mínimo, independientemente de que se realice ejercicio reglado en otros momentos: pasar ocho horas sentado en la oficina aumenta el riesgo cardiovascular incluso aunque se corra una hora al día. La obesidad, cuantificada por un índice de masa corporal (IMC = peso/altura²) superior a 30 kg/m², afecta ya al 13 % de la población mundial adulta y su prevalencia se ha triplicado desde 1975.

Las consecuencias del sedentarismo y la obesidad van más allá de la estética. Están asociados a mayor riesgo de enfermedades cardiovasculares (hipertensión, infarto, ictus), diabetes tipo 2, ciertos cánceres (colon, mama, endometrio), apnea del sueño, trastornos musculoesqueléticos y deterioro cognitivo. La actividad física regular, por el contrario, produce beneficios múltiples: mejora la función cardiovascular y metabólica, ayuda a mantener el peso, fortalece huesos y músculos, mejora el estado de ánimo y reduce la ansiedad y la depresión, mejora el sueño y la función cognitiva, y aumenta la esperanza y la calidad de vida. La OMS recomienda para adultos un mínimo de 150-300 minutos semanales de actividad aeróbica moderada o 75-150 minutos de intensa, más dos o tres sesiones semanales de fuerza. En niños y adolescentes, la recomendación asciende a al menos 60 minutos diarios de actividad moderada-intensa. Las estrategias de salud pública para combatir el sedentarismo incluyen urbanismo activo (carriles bici, zonas peatonales), transporte activo, educación física escolar de calidad, campañas informativas y políticas laborales que favorezcan las pausas activas. Es una responsabilidad compartida entre individuos, familias, escuelas, empresas, administraciones y ciudades.',
'[{"pregunta":"Según la OMS, la inactividad física es la causa de:","opciones":["Pocas muertes","Aproximadamente 3,2 millones de muertes al año en el mundo","Ninguna muerte","Solo enfermedades menores"],"correcta":1},{"pregunta":"Se considera obesidad un IMC superior a:","opciones":["20 kg/m²","25 kg/m²","30 kg/m²","40 kg/m²"],"correcta":2},{"pregunta":"Las recomendaciones de la OMS para adultos son:","opciones":["30 minutos de actividad al mes","150-300 minutos semanales de actividad aeróbica moderada + fuerza","1 hora diaria sin más","Nada específico"],"correcta":1},{"pregunta":"El sedentarismo es peligroso aunque se practique ejercicio diario porque:","opciones":["No es peligroso si se entrena","Estar sentado muchas horas aumenta el riesgo cardiovascular independientemente","No se puede compensar de ninguna forma","Siempre causa diabetes"],"correcta":1}]'::jsonb),

('ed-fisica', 'bachillerato', '{2}', 'Deporte adaptado e inclusión',
'El deporte adaptado es aquel que se modifica para permitir la práctica por personas con discapacidad (física, sensorial, intelectual o múltiple), respetando sus capacidades y garantizando la equidad en la competición. Sus orígenes modernos se sitúan en el final de la Segunda Guerra Mundial, cuando el neurólogo Ludwig Guttmann organizó en 1948 los primeros Juegos de Stoke Mandeville para veteranos con lesiones medulares, como método de rehabilitación. Coincidieron con los Juegos Olímpicos de Londres y sentaron las bases de lo que en 1960 serían los primeros Juegos Paralímpicos, celebrados en Roma con 400 deportistas. Hoy, los Juegos Paralímpicos son el segundo evento deportivo mayor del mundo y se celebran inmediatamente después de los Olímpicos en la misma sede, con más de 4000 atletas compitiendo en 22 deportes.

Los deportes se clasifican en categorías funcionales para agrupar a atletas con capacidades similares y garantizar la equidad. Existen deportes específicos para discapacidad (goalball para ciegos, boccia para personas con parálisis cerebral, rugby en silla de ruedas) y adaptaciones de deportes convencionales (natación, atletismo, esquí, ciclismo, tenis en silla). Cada deporte tiene su propio sistema de clasificación. Más allá de la competición de élite, el deporte adaptado en ámbitos escolar, recreativo y terapéutico cumple funciones fundamentales: mejora la condición física y la salud, favorece la autoestima y la autonomía personal, combate la exclusión social, desarrolla habilidades motrices y cognitivas, y aporta ejemplos de superación y esfuerzo muy valiosos como modelos sociales. La inclusión deportiva es hoy un objetivo prioritario: no basta con que existan actividades específicas, sino que debe fomentarse la participación conjunta con personas sin discapacidad siempre que sea posible, con adaptaciones razonables. Deportes inclusivos como el unihockey o el baloncesto inclusivo se diseñan desde el inicio para que personas con y sin discapacidad puedan jugar juntas en igualdad de condiciones. España es un referente en deporte paralímpico y cuenta con federaciones específicas que organizan competiciones a todos los niveles.',
'[{"pregunta":"¿Quién inició el movimiento deportivo para personas con discapacidad en 1948?","opciones":["Juan Antonio Samaranch","Ludwig Guttmann, en Stoke Mandeville","Pierre de Coubertin","Nelson Mandela"],"correcta":1},{"pregunta":"Los primeros Juegos Paralímpicos modernos se celebraron en:","opciones":["Londres 1948","Roma 1960","Barcelona 1992","Atenas 2004"],"correcta":1},{"pregunta":"La clasificación funcional en deporte adaptado sirve para:","opciones":["Excluir atletas","Agrupar atletas con capacidades similares garantizando la equidad","Aumentar la dificultad","Reducir costes"],"correcta":1},{"pregunta":"Un deporte inclusivo es aquel que:","opciones":["Es solo para discapacitados","Se diseña para que personas con y sin discapacidad jueguen juntas en igualdad","Excluye a personas sin discapacidad","No tiene adaptaciones"],"correcta":1}]'::jsonb);

